#include "game/simulation/NpcRoutineSystem.h"
namespace fw { std::vector<ActiveNpcRoutineInfo> NpcRoutineSystem::ResolveActiveRoutines(const NpcDatabase& npcDb, const RoutineDatabase& routineDb, float hour, const std::string& currentRegion) const { std::vector<ActiveNpcRoutineInfo> out; for(const auto& pair:npcDb.GetAll()){ const auto& npc=pair.second; if(npc.regionId!=currentRegion && npc.homeRegionId!=currentRegion) continue; const RoutineDefinition* routine=routineDb.Find(npc.routineId); if(!routine) continue; for(const auto& step:routine->steps){ bool wraps=step.endHour<step.startHour; bool active=wraps?(hour>=step.startHour||hour<step.endHour):(hour>=step.startHour&&hour<step.endHour); if(active){ out.push_back({npc.id,npc.displayName,npc.routineId,step.activity,step.locationTag}); break; } } } return out; } }
